import * as Environment from "../../src/lib/environment";
import { globalBaseConfig as config } from "config";

describe("getBrandFromHostname", () => {
  test.each`
    url                                      | override           | expectation
    ${new URL("https://my.sealand.com")}     | ${undefined}       | ${config.BRANDS[3]}
    ${"https://my.sealand.com"}              | ${undefined}       | ${config.BRANDS[3]}
    ${"https://my.sealand.com"}              | ${"maersk"}        | ${config.BRANDS[3]}
    ${"http://localhost:8080"}               | ${undefined}       | ${config.BRANDS[0]}
    ${"http://localhost:8080"}               | ${"sealandmaersk"} | ${config.BRANDS[2]}
    ${"http://127.0.0.1:8080"}               | ${"sealandmaersk"} | ${config.BRANDS[2]}
    ${"http://localhost:8080"}               | ${"seau"}          | ${config.BRANDS[0]}
    ${{ not: "URL" }}                        | ${undefined}       | ${config.BRANDS[0]}
    ${"jason"}                               | ${undefined}       | ${config.BRANDS[0]}
    ${""}                                    | ${undefined}       | ${config.BRANDS[0]}
    ${"http://cdt.developer.hamburgsud.com"} | ${undefined}       | ${config.BRANDS[7]}
    ${"http://cdt.developer.hamburgsud.io"}  | ${undefined}       | ${config.BRANDS[7]}
    ${"https://www.sealandmaersk.com.cn"}    | ${undefined}       | ${config.BRANDS[2]}
  `("should return the correct brand from the url $url and override $override", ({ url, override, expectation }) => {
    expect(Environment.getBrandFromHostname(url, override)).toEqual(expectation);
  });
});

describe("isLocalhost", () => {
  test.each`
    hostname       | expectation
    ${"maersk"}    | ${false}
    ${"localhost"} | ${true}
    ${"127.0.0.1"} | ${true}
    ${"0.0.0.0"}   | ${true}
  `("Determines if $hostname is localhosty", ({ hostname, expectation }) => {
    expect(Environment.isLocalhost(hostname)).toBe(expectation);
  });
});

describe("getBetaFromHostname", () => {
  test.each`
    url                                    | expected
    ${new URL("https://beta.maersk.com")}  | ${true}
    ${new URL("https://my.sealand.com")}   | ${false}
    ${"https://beta.sealandmaersk.com"}    | ${true}
    ${"https://my.sealand.com"}            | ${false}
    ${"https://www.maersklinelimited.com"} | ${false}
    ${"json"}                              | ${false}
    ${"https://www.sealandmaersk.com.cn"}  | ${false}
  `("Should return $expected for $url", ({ url, expected }) => {
    expect(Environment.getBetaFromHostname(url)).toBe(expected);
  });
});

describe("isChinaDomain", () => {
  test.each`
    url                                    | expected
    ${"https://beta.maersk.com"}           | ${false}
    ${"https://my.sealand.com"}            | ${false}
    ${"maersk.com"}                        | ${false}
    ${"sealandmaersk.com.cn"}              | ${true}
    ${"beta.maersk.com.cn"}                | ${true}
    ${"https://www.maersklinelimited.com"} | ${false}
    ${"json"}                              | ${false}
    ${"https://www.sealandmaersk.com.cn"}  | ${true}
  `("Should return $expected for $url", ({ url, expected }) => {
    expect(Environment.isChinaDomain(url)).toBe(expected);
  });
});
describe("setFaviconByBrand", () => {
  afterEach(() => {
    document.querySelector("link") && document.querySelector("link").remove();
  });
  test.each`
    brand
    ${config.BRANDS[0]}
    ${config.BRANDS[3]}
    ${config.BRANDS[5]}
  `("should set the favicon based on the brand object passed", ({ brand }) => {
    Environment.setFaviconByBrand(brand);
    expect(document.querySelector("link").href).toBe(
      `https://assetst.maerskline.com/img/fav-icons/${brand.brandName}.ico`
    );
  });
  it("should do nothing if given an object without a brandName", () => {
    Environment.setFaviconByBrand({
      domain: "maersk.com"
    });
    expect(document.querySelector("link")).toBe(null);
  });
  it("should do nothing if not given an object", () => {
    Environment.setFaviconByBrand("hello");
    expect(document.querySelector("link")).toBe(null);
  });
});

